SELECT * FROM (
    SELECT t.*, ROWNUM rn FROM (
        SELECT * FROM DEVICE

            AND DEVICE_NAME LIKE '%' || #{deviceName} || '%'
            AND DEVICE_TYPE = #{deviceType}
            AND SHOP_ID = #{shopId}
            AND STATUS = #{status}

        ORDER BY DEVICE_ID DESC
    ) t WHERE ROWNUM <= #{offset} + #{limit}
) WHERE rn > #{offset}

SELECT COUNT(*) FROM DEVICE

    AND DEVICE_NAME LIKE '%' || #{deviceName} || '%'
    AND DEVICE_TYPE = #{deviceType}
    AND SHOP_ID = #{shopId}
    AND STATUS = #{status}

