UPDATE DEVICE SET
    DEVICE_NO = #{deviceNo}, DEVICE_NAME = #{deviceName}, DEVICE_TYPE = #{deviceType},
    SHOP_ID = #{shopId}, STATUS = #{status}
WHERE DEVICE_ID = #{deviceId}
